import React, { useCallback, useMemo, useState } from 'react';
import { Button, NumberInput } from '@linm-soft-org/linm-web-common-components';
import styles from './FpcCostDeclarePage.module.css';

const TEST_ID = 'fpc-cost-declare';

/* ── Format helpers ──────────────────────── */
const fVnd = (v: number): string =>
  new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND', maximumFractionDigits: 0 }).format(v);

const fCompact = (v: number): string => {
  const abs = Math.abs(v);
  if (abs >= 1_000_000_000) return `${(abs / 1_000_000_000).toFixed(1)} tỷ`;
  if (abs >= 1_000_000) return `${(abs / 1_000_000).toFixed(0)} triệu`;
  if (abs >= 1_000) return `${(abs / 1_000).toFixed(0)} nghìn`;
  return `${abs.toLocaleString('vi-VN')}`;
};

const todayStr = () => new Date().toISOString().slice(0, 10);

/* ── Mock data ───────────────────────────── */
const MOCK_COST_CODES: { code: string; name: string; group: string }[] = [
  { code: 'CP001', name: 'Tiền thuê mặt bằng', group: 'Chi phí cố định' },
  { code: 'CP002', name: 'Lương nhân viên', group: 'Chi phí nhân sự' },
  { code: 'CP003', name: 'Điện nước và dịch vụ', group: 'Chi phí vận hành' },
  { code: 'CP004', name: 'Vận chuyển và hậu cần', group: 'Chi phí vận hành' },
  { code: 'CP005', name: 'Tiếp thị và quảng cáo', group: 'Chi phí bán hàng' },
  { code: 'CP006', name: 'Bảo trì và sửa chữa', group: 'Chi phí vận hành' },
  { code: 'CP007', name: 'Văn phòng phẩm', group: 'Chi phí quản lý' },
  { code: 'CP008', name: 'Phí ngân hàng', group: 'Chi phí tài chính' },
  { code: 'CP009', name: 'Thuế và phí', group: 'Chi phí bắt buộc' },
  { code: 'CP010', name: 'Đào tạo nhân viên', group: 'Chi phí nhân sự' },
  { code: 'CP011', name: 'Bảo hiểm', group: 'Chi phí nhân sự' },
  { code: 'CP012', name: 'Công cụ dụng cụ', group: 'Chi phí vận hành' },
];

const MOCK_CUSTOMERS: { code: string; name: string; group: string }[] = [
  { code: 'KH001', name: 'Công ty TNHH Thực phẩm Xanh', group: 'Nhà cung cấp nguyên liệu' },
  { code: 'KH002', name: 'Chi nhánh Nguyễn Huệ', group: 'Cửa hàng' },
  { code: 'KH003', name: 'Công ty Vận tải Sao Mai', group: 'Nhà cung cấp dịch vụ' },
  { code: 'KH004', name: 'Chi nhánh Lê Văn Sỹ', group: 'Cửa hàng' },
  { code: 'KH005', name: 'Công ty Điện lực TP.HCM', group: 'Tiện ích' },
  { code: 'KH006', name: 'Công ty Cấp nước Sài Gòn', group: 'Tiện ích' },
  { code: 'KH007', name: 'Công ty Quảng cáo Đại Phát', group: 'Đối tác' },
  { code: 'KH008', name: 'NCC Văn phòng phẩm An Khang', group: 'Nhà cung cấp vật tư' },
  { code: 'KH009', name: 'Bảo hiểm Bảo Việt', group: 'Bảo hiểm' },
  { code: 'KH010', name: 'Trung tâm Đào tạo Minh Trí', group: 'Đối tác' },
];

type GroupMode = 'cost-code' | 'customer';

/* ── Line type ───────────────────────────── */
interface DailyPlanLine {
  id: string;
  entityCode: string;
  entityName: string;
  entityGroup: string;
  amount: number;
  note: string;
}

const createLinesFrom = (src: { code: string; name: string; group: string }[]): DailyPlanLine[] =>
  src.slice(0, 6).map((s, i) => ({
    id: `line-${i}`,
    entityCode: s.code,
    entityName: s.name,
    entityGroup: s.group,
    amount: 0,
    note: '',
  }));

const SAMPLE_COST_CODE: Record<string, number> = {
  'CP001': 150_000_000, 'CP002': 280_000_000, 'CP003': 92_000_000,
  'CP004': 75_000_000, 'CP005': 50_000_000, 'CP006': 35_000_000,
  'CP007': 12_000_000, 'CP008': 6_000_000, 'CP009': 55_000_000,
  'CP010': 25_000_000, 'CP011': 22_000_000, 'CP012': 18_000_000,
};

const SAMPLE_CUSTOMER: Record<string, number> = {
  'KH001': 125_000_000, 'KH002': 85_000_000, 'KH003': 45_000_000,
  'KH004': 70_000_000, 'KH005': 28_000_000, 'KH006': 15_000_000,
  'KH007': 40_000_000, 'KH008': 12_000_000, 'KH009': 22_000_000,
  'KH010': 18_000_000,
};

/* ── Component ────────────────────────────── */
const FpcCostDeclarePage: React.FC = () => {
  /* ── Header state ──────────────────────── */
  const [planDate, setPlanDate] = useState(todayStr());
  const [branchCode, setBranchCode] = useState('HQ');
  const [createdBy, setCreatedBy] = useState('Nguyễn Văn A');
  const [description, setDescription] = useState('Dự kiến chi trong ngày');
  const [saving, setSaving] = useState(false);
  const [saved, setSaved] = useState(false);

  /* ── Mode ──────────────────────────────── */
  const [groupMode, setGroupMode] = useState<GroupMode>('cost-code');
  const [lines, setLines] = useState<DailyPlanLine[]>(createLinesFrom(MOCK_COST_CODES));

  const currentSource = groupMode === 'cost-code' ? MOCK_COST_CODES : MOCK_CUSTOMERS;

  const handleToggleMode = useCallback((mode: GroupMode) => {
    if (mode === groupMode) return;
    setGroupMode(mode);
    setLines(createLinesFrom(mode === 'cost-code' ? MOCK_COST_CODES : MOCK_CUSTOMERS));
  }, [groupMode]);

  /* ── Line handlers ─────────────────────── */
  const handleLineChange = useCallback((id: string, field: keyof DailyPlanLine, value: string | number) => {
    setLines(prev => prev.map(line =>
      line.id === id ? { ...line, [field]: value } : line
    ));
  }, []);

  const handleAddLine = useCallback(() => {
    const usedCodes = lines.map(l => l.entityCode);
    const unused = currentSource.find(s => !usedCodes.includes(s.code));
    if (!unused) return;
    setLines(prev => [...prev, {
      id: `line-${Date.now()}`,
      entityCode: unused.code,
      entityName: unused.name,
      entityGroup: unused.group,
      amount: 0,
      note: '',
    }]);
  }, [lines, currentSource]);

  const handleRemoveLine = useCallback((id: string) => {
    setLines(prev => prev.filter(line => line.id !== id));
  }, []);

  /* ── Fill sample ───────────────────────── */
  const handleFillSample = useCallback(() => {
    setLines(prev => prev.map(line => {
      const map = groupMode === 'cost-code' ? SAMPLE_COST_CODE : SAMPLE_CUSTOMER;
      const amount = map[line.entityCode] || 0;
      return { ...line, amount };
    }));
  }, [groupMode]);

  /* ── Save / Print ──────────────────────── */
  const handleSave = useCallback(async () => {
    setSaving(true);
    await new Promise(r => setTimeout(r, 600));
    setSaving(false);
    setSaved(true);
    setTimeout(() => setSaved(false), 3000);
  }, []);

  const handlePrint = useCallback(() => {
    const el = document.getElementById('cost-declare-content');
    if (!el) return;
    const win = window.open('', '_blank');
    if (!win) return;
    win.document.write([
      '<html><head><title>Phiếu dự kiến chi theo ngày</title><style>',
      'body{font-family:Arial,sans-serif;padding:20px;color:#1e293b}',
      'table{width:100%;border-collapse:collapse;margin:16px 0}',
      'th,td{padding:8px 12px;border:1px solid #e2e8f0;text-align:left;font-size:12px}',
      'th{background:#f8fafc;font-weight:600}',
      'h1{font-size:22px;color:#059669}',
      '.right{text-align:right}.money{font-family:monospace;text-align:right}',
      '.demo-badge{display:inline-block;padding:2px 8px;border-radius:4px;font-size:11px;background:#fef3c7;color:#92400e}',
      '</style></head><body>',
      '<h1>Phiếu dự kiến chi theo ngày <span class="demo-badge">DỮ LIỆU MÔ PHỎNG</span></h1>',
      '<p>Ngày in: ' + new Date().toLocaleString('vi-VN') + '</p>',
      el.innerHTML,
      '</body></html>',
    ].join('\n'));
    win.document.close();
    win.print();
  }, []);

  /* ── Computed ──────────────────────────── */
  const totalAmount = lines.reduce((s, l) => s + l.amount, 0);
  const activeCount = lines.filter(l => l.amount > 0).length;

  /* ── Group lines for display ───────────── */
  const groupedLines = useMemo(() => {
    const map = new Map<string, DailyPlanLine[]>();
    lines.forEach(line => {
      const g = line.entityGroup || 'Khác';
      if (!map.has(g)) map.set(g, []);
      map.get(g)!.push(line);
    });
    return Array.from(map.entries()).map(([group, items]) => ({
      group,
      items,
      total: items.reduce((s, i) => s + i.amount, 0),
    }));
  }, [lines]);

  const NOW = new Date();
  const dateLabel = `${planDate.slice(8, 10)}/${planDate.slice(5, 7)}/${planDate.slice(0, 4)}`;

  /* ── Render ────────────────────────────── */
  return (
    <div className={styles.page} data-form-page data-testid={`${TEST_ID}-page`}>
      {/* ── Page header ── */}
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}>
            <i className="fas fa-calendar-day" />
            Dự kiến chi theo ngày
          </h1>
          <p className={styles.subtitle}>
            Nhập dự kiến chi theo ngày — theo mã chi phí hoặc đối tượng
            <span className={styles.phaseTag} style={{ marginLeft: 8, background: '#fef3c7', color: '#92400e' }}>DỮ LIỆU MÔ PHỎNG</span>
          </p>
        </div>
        <div className={styles.toolbar}>
          <Button variant="primary" disabled={saving} onClick={handleSave} data-testid={`${TEST_ID}-save-btn`}>
            <i className="fas fa-save" style={{ marginRight: 6 }} />
            {saving ? 'Đang lưu...' : 'Lưu'}
          </Button>
          <Button onClick={handlePrint} data-testid={`${TEST_ID}-print-btn`}>
            <i className="fas fa-print" style={{ marginRight: 6 }} />
            In
          </Button>
          <Button onClick={() => { setLines(createLinesFrom(currentSource)); setSaved(false); }}>
            <i className="fas fa-redo" style={{ marginRight: 6 }} />
            Làm mới
          </Button>
          {saved && (
            <span style={{ display: 'inline-flex', alignItems: 'center', gap: 6, padding: '6px 14px', background: '#d1fae5', color: '#065f46', borderRadius: 8, fontSize: 13, fontWeight: 600 }}>
              <i className="fas fa-check-circle" />
              Đã lưu dữ liệu mô phỏng
            </span>
          )}
        </div>
      </div>

      <div className={styles.formShell} id="cost-declare-content">
        {/* ── Header info ── */}
        <div className={styles.sectionCard}>
          <div className={styles.sectionHeader}>
            <h2 className={styles.sectionTitle}>
              <i className="fas fa-info-circle" style={{ color: '#059669' }} />
              Thông tin chung
            </h2>
            <span className={styles.sectionBadge}>Dự kiến chi ngày {dateLabel}</span>
          </div>
          <div className={styles.headerGrid}>
            <div className={styles.fieldGroup}>
              <label className={styles.fieldLabel}>Ngày dự kiến</label>
              <input type="date" className={styles.fieldInput} value={planDate} onChange={e => setPlanDate(e.target.value)} data-testid={`${TEST_ID}-date`} />
            </div>
            <div className={styles.fieldGroup}>
              <label className={styles.fieldLabel}>Chi nhánh</label>
              <select className={styles.fieldSelect} value={branchCode} onChange={e => setBranchCode(e.target.value)} data-testid={`${TEST_ID}-branch`}>
                <option value="HQ">Trụ sở chính</option>
                <option value="FM01">FM01 - Lê Văn Sỹ</option>
                <option value="FM02">FM02 - Nguyễn Huệ</option>
                <option value="FM03">FM03 - Lý Tự Trọng</option>
                <option value="FM04">FM04 - Trần Hưng Đạo</option>
                <option value="FM05">FM05 - Nguyễn Văn Linh</option>
              </select>
            </div>
            <div className={styles.fieldGroup}>
              <label className={styles.fieldLabel}>Người lập</label>
              <input className={styles.fieldInput} value={createdBy} onChange={e => setCreatedBy(e.target.value)} data-testid={`${TEST_ID}-creator`} />
            </div>
            <div className={styles.fieldGroup}>
              <label className={styles.fieldLabel}>Trạng thái</label>
              <div className={styles.fieldValue} style={{ fontSize: 13, fontWeight: 600, color: '#d97706' }}>
                <i className="fas fa-pen" style={{ marginRight: 6 }} />
                Bản nháp
              </div>
            </div>
            <div className={styles.fieldGroup} style={{ gridColumn: '1 / -1' }}>
              <label className={styles.fieldLabel}>Diễn giải</label>
              <input className={styles.fieldInput} value={description} onChange={e => setDescription(e.target.value)} placeholder="Nhập diễn giải" data-testid={`${TEST_ID}-desc`} />
            </div>
          </div>
        </div>

        {/* ── Summary bar ── */}
        <div className={styles.statsRow}>
          <div className={styles.statCard}>
            <span className={styles.statLabel}>Ngày</span>
            <span className={styles.statValue}>{dateLabel}</span>
          </div>
          <div className={styles.statCard}>
            <span className={styles.statLabel}>Tổng dự kiến chi</span>
            <span className={`${styles.statValue} ${totalAmount > 0 ? styles.negative : ''}`}>{fCompact(totalAmount)}</span>
          </div>
          <div className={styles.statCard}>
            <span className={styles.statLabel}>Số khoản</span>
            <span className={styles.statValue}>{lines.length}</span>
          </div>
          <div className={styles.statCard}>
            <span className={styles.statLabel}>Có số liệu</span>
            <span className={`${styles.statValue} ${activeCount > 0 ? styles.positive : ''}`}>{activeCount}</span>
          </div>
        </div>

        {/* ── Mode toggle ── */}
        <div className={styles.sectionCard}>
          <div className={styles.sectionHeader}>
            <h2 className={styles.sectionTitle}>
              <i className="fas fa-list" style={{ color: '#059669' }} />
              Khoản dự kiến chi
            </h2>
            <div style={{ display: 'flex', gap: 6 }}>
              <button
                onClick={() => handleToggleMode('cost-code')}
                style={{
                  padding: '6px 16px', borderRadius: 8, border: '1px solid #e2e8f0', fontSize: 13, fontWeight: 600, cursor: 'pointer', transition: 'all 0.2s',
                  background: groupMode === 'cost-code' ? '#059669' : '#fff',
                  color: groupMode === 'cost-code' ? '#fff' : '#64748b',
                }}
              >Theo mã chi phí</button>
              <button
                onClick={() => handleToggleMode('customer')}
                style={{
                  padding: '6px 16px', borderRadius: 8, border: '1px solid #e2e8f0', fontSize: 13, fontWeight: 600, cursor: 'pointer', transition: 'all 0.2s',
                  background: groupMode === 'customer' ? '#059669' : '#fff',
                  color: groupMode === 'customer' ? '#fff' : '#64748b',
                }}
              >Theo đối tượng</button>
            </div>
          </div>

          {/* Fill sample prompt */}
          <div style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '12px 16px', background: '#f0fdf4', borderRadius: 10, border: '1px dashed #86efac', marginBottom: 16 }}>
            <i className="fas fa-lightbulb" style={{ color: '#059669', fontSize: 16 }} />
            <span style={{ flex: 1, fontSize: 13, color: '#065f46' }}>
              Nhập số liệu thủ công hoặc nhấn <strong>"Điền dữ liệu mẫu"</strong> để xem trước
            </span>
            <Button onClick={handleFillSample}>
              <i className="fas fa-magic" style={{ marginRight: 6 }} />
              Điền dữ liệu mẫu
            </Button>
          </div>

          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th style={{ width: 36 }}>STT</th>
                  <th style={{ width: 100 }}>Mã</th>
                  <th>Tên {groupMode === 'cost-code' ? 'chi phí' : 'đối tượng'}</th>
                  <th className={styles.colRight} style={{ width: 150 }}>Dự kiến chi</th>
                  <th>Ghi chú</th>
                  <th style={{ width: 36 }}></th>
                </tr>
              </thead>
              <tbody>
                {groupedLines.map(g => (
                  <React.Fragment key={g.group}>
                    <tr style={{ background: '#f8fafc' }}>
                      <td colSpan={6} style={{ padding: '6px 14px', fontSize: 12, fontWeight: 600, color: '#059669', letterSpacing: 0.3 }}>
                        {g.group} — {fCompact(g.total)}
                      </td>
                    </tr>
                    {g.items.map((line, idx) => (
                      <tr key={line.id}>
                        <td style={{ textAlign: 'center', color: '#94a3b8', fontWeight: 500 }}>{idx + 1}</td>
                        <td style={{ fontWeight: 500, color: '#1e293b', fontSize: 12 }}>{line.entityCode}</td>
                        <td style={{ color: '#475569' }}>{line.entityName}</td>
                        <td>
                          <NumberInput
                            className={styles.lineInput}
                            value={line.amount}
                            onChange={v => handleLineChange(line.id, 'amount', v)}
                            placeholder="0"
                          />
                        </td>
                        <td>
                          <input
                            className={`${styles.lineInput} ${styles.lineInputFull}`}
                            value={line.note}
                            onChange={e => handleLineChange(line.id, 'note', e.target.value)}
                            placeholder="Ghi chú"
                            style={{ textAlign: 'left' }}
                          />
                        </td>
                        <td style={{ textAlign: 'center' }}>
                          <button onClick={() => handleRemoveLine(line.id)} style={{ border: 'none', background: 'none', color: '#ef4444', cursor: 'pointer', fontSize: 14, padding: 4 }} title="Xóa dòng">
                            <i className="fas fa-times" />
                          </button>
                        </td>
                      </tr>
                    ))}
                  </React.Fragment>
                ))}
              </tbody>
            </table>
          </div>

          <div style={{ marginTop: 12, display: 'flex', gap: 8 }}>
            <Button onClick={handleAddLine} disabled={lines.length >= currentSource.length}>
              <i className="fas fa-plus" style={{ marginRight: 6 }} />
              Thêm dòng
            </Button>
          </div>
        </div>

        {/* ── Footer totals ── */}
        <div className={styles.footerRow}>
          <div className={styles.footerItem}>
            <span className={styles.footerLabel}>Ngày</span>
            <span className={styles.footerValue} style={{ fontSize: 16 }}>{dateLabel}</span>
          </div>
          <div className={styles.footerItem}>
            <span className={styles.footerLabel}>Tổng dự kiến chi</span>
            <span className={`${styles.footerValue} ${totalAmount > 0 ? styles.negative : ''}`}>{fVnd(totalAmount)}</span>
          </div>
          <div className={styles.footerItem}>
            <span className={styles.footerLabel}>Số khoản</span>
            <span className={styles.footerValue}>{lines.length}</span>
          </div>
          <div className={styles.footerItem}>
            <span className={styles.footerLabel}>Chi nhánh</span>
            <span className={styles.footerValue} style={{ fontSize: 16 }}>{branchCode}</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default FpcCostDeclarePage;
